    target = entry.impls.get(sel) or entry.fallbacks.get(sel) or entry.wildcard_fallback
    if target is None:
        return _C._redispatch_boxed_current(*args)
    try:
        out = target(*args, **kwargs)
    except NotImplementedError:
        return _C._redispatch_boxed_current(*args)
    if out is NotImplemented:
        return _C._redispatch_boxed_current(*args)
    return out

return _override

