    return False

prev = base_cls.current()
try:
    try:
        base_cls.set_current_with_device(base)
    except Exception:
        base_cls.set_current(base)
    return bool(_cuda_isCurrentStreamCapturing())
finally:
    # Best-effort restore; errors suppressed to avoid masking user errors.
